var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양, 도와드릴까요?","JPN":"ミナさん、手伝いましょうか？","ENG":"Need a hand, Mina?","TWN":"米娜小姐，需要幫忙嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"괜찮아, 선배! 이 정도는 내가 처리할 수 있어!","JPN":"大丈夫、先輩！　これくらい一人で処理できる！","ENG":"It's okay! I've got this!","TWN":"不用了，前輩！這種程度，我自己就能處理了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이야, 그래도 조금은 고전하지 않을까 생각했는데......","JPN":"いや～少しは苦戦すると思ったのに……","ENG":"Honestly, I thought you'd struggle at least a little bit...","TWN":"哎呀，本來以為會苦戰一番的……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이젠 정말 가르쳐 드릴 게 없네요.","JPN":"もはや教えることがないレベルですね。","ENG":"But now I see there's nothing else for me to teach you anymore.","TWN":"現在真的沒什麼可教你的了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 정도는 아니야. 아직 선배나 소대장에 비하면 멀었지.","JPN":"それほどではないよ。先輩や小隊長に比べたらまだまだだよ。","ENG":"Well, I wouldn't go that far. I still have much to learn, compared to you or the Commander.","TWN":"過獎了，比起前輩和小隊長，我還差得遠呢。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어......","JPN":"え……","ENG":"Um...","TWN":"額……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양이 그렇게 말씀하시니까 적응이 잘 안 되네요.","JPN":"ミナさんのそんな台詞はなかなか聞き慣れませんね。","ENG":"I really can't get used to all this humility from you.","TWN":"米娜小姐這麼謙虛，我有些不適應呢。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제가 아는 미나 양이라면 분명......","JPN":"僕の知るミナさんなら……","ENG":"The Mina I used to know would say something like...","TWN":"如果是以前，你肯定會……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>생각보다 시시했어, 그리고 친한 척 하지 말고 좀 떨어져 줄래?</color>","JPN":"<color=#ffd34c>大したことない。あと、馴れ馴れしくしないでちょっと離れてくれる？</color>","ENG":"<color=#ffd34c>That was kinda lame. And can you stop acting so chummy and give me some personal space?</color>","TWN":"<color=#ffd34c>比想象中還要無聊，而且不要假裝跟我很熟，能離我遠點嗎？</color>"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"라고 하셨을 것 같은데 말이죠.","JPN":"と言いそうなのに。","ENG":"Don't you agree?","TWN":"這樣說的吧。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"또, 또 그런다! 예전 이야기는 꺼내지 말라니까!","JPN":"また言うの？　だから、昔の話はもういいって！","ENG":"Hey, stop it! I told you not to bring up the past!","TWN":"你又來了！都說了別再提以前的事了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"칭찬하는 겁니다. 지금의 미나 양은 그때보다 훨씬 성장했으니까요.","JPN":"褒めているんですよ。今のミナさんはあの時よりずっと成長していますから。","ENG":"It's a compliment. You've come a long way since then.","TWN":"我這是在誇你呢。現在的米娜小姐已經今非昔比了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"뭐니뭐니 해도 그 리플레이서 킹을 단독으로 쓰러트린 실력이잖아요?","JPN":"何よりも、あのリプレイサー・キングを単独で倒した腕前でしょう？","ENG":"After all, you defeated the Replacer King all on your own.","TWN":"不管怎樣，你現在可以獨自一人打敗克隆·帝皇了，不是嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이젠 서류상으로만 C급이지, 충분히 A급 이상의 카운터로 인정받을 만해요.","JPN":"もう書類上Cランクなだけで、十分Aランク以上のカウンターとして認められてもいいでしょう。","ENG":"You're only Grade C on paper now. You've got what it takes to be designated Grade A or above.","TWN":"雖然書面上還是C級，但充分有資格成為A級以上制裁者了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......하지만 세상 일에는 바로 그 서류가 중요한 거라고 부사장님이 말하던 걸.","JPN":"……でも社会ではその書類が重要って副社長が言っていたよ。","ENG":"But the Vice President said the paperwork is what matters when it comes to the real world.","TWN":"……可是副總常說，書面憑證才是最重要的。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};